mapper.select:
SELECT a.id, a.project_id AS "projectId", a.style, a.budget, a.member, a.mark, a.signature_url AS "signatureUrl", a.signed_at AS "signedAt", a.status, a.created_by AS "createdBy", a.updated_by AS "updatedBy", a.created_at AS "createdAt", a.updated_at AS "updatedAt", p.code AS "projectCode", p.name AS "projectName", creator.name AS "createdByName", updater.name AS "updatedByName", CASE a.status WHEN 1 THEN '待提交' WHEN 2 THEN '待审核' WHEN 3 THEN '已完成' ELSE '' END AS "statusText" FROM requirement a LEFT JOIN project p ON p.id = a.project_id LEFT JOIN sys_account creator ON creator.id = a.created_by LEFT JOIN sys_account updater ON updater.id = a.updated_by
AND a.project_id = #{params.projectId}
AND p.name LIKE CONCAT('%', #{params.projectName}, '%') AND p.name LIKE '%' || #{params.projectName} || '%'
AND a.status = #{params.status}
ORDER BY a.updated_at DESC, a.id DESC
